create table dirkspzm32.aps_fa_vorgangs_position (
    plannr                     varchar2(50 char),
    ergebnisnr                 varchar2(50 char),
    fakopfnr                   varchar2(50 char),
    favorgangsnr               varchar2(50 char),
    favorgangsalternative      varchar2(50 char),
    favorgangssplittnr         number(*, 5),
    favorgangspositionsnr      varchar2(50 char),
    favorgangspositionsinfo1   varchar2(255 char),
    favorgangspositionsinfo2   varchar2(255 char),
    favorgangspositionsinfo3   varchar2(255 char),
    apvorgangsbeschreibung     varchar2(255 char),
    apvorgangscustominfo1      varchar2(255 char),
    apvorgangscustominfo2      varchar2(255 char),
    apvorgangscustominfo3      varchar2(255 char),
    apvorgangsposbeschreibung  varchar2(255 char),
    apvorgangsposcustominfo1   varchar2(255 char),
    apvorgangsposcustominfo2   varchar2(255 char),
    apvorgangsposcustominfo3   varchar2(255 char),
    typ                        number(*, 0),
    typbeschreibung            varchar2(50 char),
    status                     number(*, 5),
    statusbeschreibung         varchar2(50 char),
    planstart                  varchar2(19 char),
    planende                   varchar2(19 char),
    bruttomenge                number(*, 3),
    nettomenge                 number(*, 3),
    einheitsnr                 varchar2(50 char),
    einheitsbezeichnung        varchar2(50 char),
    wert                       number(*, 5),
    planfruehesterstart        varchar2(19 char),
    planspaetesterstart        varchar2(19 char),
    planfruehestesende         varchar2(19 char),
    planspaetestesende         varchar2(19 char),
    planfruehesterstartinitial varchar2(19 char),
    planspaetesterstartinitial varchar2(19 char),
    planfruehestesendeinitial  varchar2(19 char),
    planspaetestesendeinitial  varchar2(19 char),
    planfruehesterstartfinal   varchar2(19 char),
    planspaetesterstartfinal   varchar2(19 char),
    planfruehestesendefinal    varchar2(19 char),
    planspaetestesendefinal    varchar2(19 char),
    erp_u_status               varchar2(2 char) default 'N' not null enable,
    plan_res_name              varchar2(25 char),
    fixiert                    number(*, 5),
    letzterueckmeldung         varchar2(19 char),
    prozenterledigt            number(*, 6),
    favorgangsname             varchar2(50 char)
);


